#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>

#include "common.h"

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

static void lud_diagonal(float *m, int matrix_dim, int offset)
{
    float shadow[BLOCK_SIZE * BLOCK_SIZE];
    int i, j, tx;
    int array_offset = offset * matrix_dim + offset;

    // Parallelize the copy to local memory (shadow)
    #pragma omp parallel for private(i, tx, array_offset)
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int local_offset = offset * matrix_dim + offset + tx;
        for (i = 0; i < BLOCK_SIZE; i++) {
            shadow[i * BLOCK_SIZE + tx] = m[local_offset];
            local_offset += matrix_dim;
        }
    }

    // LUD computation on the diagonal block
    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        #pragma omp parallel for private(j, tx)
        for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
            float sum = 0.0f;
            for (j = 0; j < i; j++) {
                sum += shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
            }
            shadow[tx * BLOCK_SIZE + i] -= sum;
            shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
        }

        #pragma omp parallel for private(j, tx)
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            float sum = 0.0f;
            for (j = 0; j < i + 1; j++) {
                sum += shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
            }
            shadow[(i + 1) * BLOCK_SIZE + tx] -= sum;
        }
    }

    // Write back to global memory
    #pragma omp parallel for private(i, tx, array_offset)
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int local_offset = (offset + 1) * matrix_dim + offset + tx;
        for (i = 1; i < BLOCK_SIZE; i++) {
            m[local_offset] = shadow[i * BLOCK_SIZE + tx];
            local_offset += matrix_dim;
        }
    }
}

static void lud_perimeter(float *m, int matrix_dim, int offset, int bx)
{
    float dia[BLOCK_SIZE * BLOCK_SIZE];
    float peri_row[BLOCK_SIZE * BLOCK_SIZE];
    float peri_col[BLOCK_SIZE * BLOCK_SIZE];
    int i, j, idx, array_offset;

    // Load diagonal block (split between threads)
    #pragma omp parallel for private(i, idx, array_offset)
    for (idx = 0; idx < BLOCK_SIZE; idx++) {
        array_offset = offset * matrix_dim + offset + idx;
        for (i = 0; i < BLOCK_SIZE / 2; i++) {
            dia[i * BLOCK_SIZE + idx] = m[array_offset];
            array_offset += matrix_dim;
        }
    }

    #pragma omp parallel for private(i, idx, array_offset)
    for (idx = 0; idx < BLOCK_SIZE / 2; idx++) {
        array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset + idx;
        for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
            dia[i * BLOCK_SIZE + idx] = m[array_offset];
            array_offset += matrix_dim;
        }
    }

    // Load perimeter row
    #pragma omp parallel for private(i, idx, array_offset)
    for (idx = 0; idx < BLOCK_SIZE; idx++) {
        array_offset = offset * matrix_dim + (bx + 1) * BLOCK_SIZE + idx;
        for (i = 0; i < BLOCK_SIZE; i++) {
            peri_row[i * BLOCK_SIZE + idx] = m[array_offset];
            array_offset += matrix_dim;
        }
    }

    // Load perimeter column
    #pragma omp parallel for private(i, idx, array_offset)
    for (idx = 0; idx < BLOCK_SIZE / 2; idx++) {
        array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset + idx;
        for (i = 0; i < BLOCK_SIZE; i++) {
            peri_col[idx * BLOCK_SIZE + i] = m[array_offset];
            array_offset += matrix_dim;
        }
    }

    #pragma omp parallel for private(i, idx, array_offset)
    for (idx = BLOCK_SIZE / 2; idx < BLOCK_SIZE; idx++) {
        array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset + idx;
        for (i = 0; i < BLOCK_SIZE; i++) {
            peri_col[idx * BLOCK_SIZE + i] = m[array_offset];
            array_offset += matrix_dim;
        }
    }

    // Update perimeter row
    #pragma omp parallel for private(i, j, idx)
    for (idx = 0; idx < BLOCK_SIZE; idx++) {
        for (i = 1; i < BLOCK_SIZE; i++) {
            float sum = 0.0f;
            for (j = 0; j < i; j++) {
                sum += dia[i * BLOCK_SIZE + j] * peri_row[j * BLOCK_SIZE + idx];
            }
            peri_row[i * BLOCK_SIZE + idx] -= sum;
        }
    }

    // Update perimeter column
    #pragma omp parallel for private(i, j, idx)
    for (idx = 0; idx < BLOCK_SIZE / 2; idx++) {
        for (i = 0; i < BLOCK_SIZE; i++) {
            float sum = 0.0f;
            for (j = 0; j < i; j++) {
                sum += peri_col[idx * BLOCK_SIZE + j] * dia[j * BLOCK_SIZE + i];
            }
            peri_col[idx * BLOCK_SIZE + i] -= sum;
            peri_col[idx * BLOCK_SIZE + i] /= dia[i * BLOCK_SIZE + i];
        }
    }

    #pragma omp parallel for private(i, j, idx)
    for (idx = BLOCK_SIZE / 2; idx < BLOCK_SIZE; idx++) {
        for (i = 0; i < BLOCK_SIZE; i++) {
            float sum = 0.0f;
            for (j = 0; j < i; j++) {
                sum += peri_col[idx * BLOCK_SIZE + j] * dia[j * BLOCK_SIZE + i];
            }
            peri_col[idx * BLOCK_SIZE + i] -= sum;
            peri_col[idx * BLOCK_SIZE + i] /= dia[i * BLOCK_SIZE + i];
        }
    }

    // Write back perimeter row
    #pragma omp parallel for private(i, idx, array_offset)
    for (idx = 0; idx < BLOCK_SIZE; idx++) {
        array_offset = (offset + 1) * matrix_dim + (bx + 1) * BLOCK_SIZE + idx;
        for (i = 1; i < BLOCK_SIZE; i++) {
            m[array_offset] = peri_row[i * BLOCK_SIZE + idx];
            array_offset += matrix_dim;
        }
    }

    // Write back perimeter column
    #pragma omp parallel for private(i, idx, array_offset)
    for (idx = 0; idx < BLOCK_SIZE / 2; idx++) {
        array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset + idx;
        for (i = 0; i < BLOCK_SIZE; i++) {
            m[array_offset] = peri_col[i * BLOCK_SIZE + idx];
            array_offset += matrix_dim;
        }
    }

    #pragma omp parallel for private(i, idx, array_offset)
    for (idx = BLOCK_SIZE / 2; idx < BLOCK_SIZE; idx++) {
        array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset + idx;
        for (i = 0; i < BLOCK_SIZE; i++) {
            m[array_offset] = peri_col[i * BLOCK_SIZE + idx];
            array_offset += matrix_dim;
        }
    }
}

static void lud_internal(float *m, int matrix_dim, int offset, int bx, int by)
{
    float peri_row[BLOCK_SIZE * BLOCK_SIZE];
    float peri_col[BLOCK_SIZE * BLOCK_SIZE];
    int global_row_id = offset + (by + 1) * BLOCK_SIZE;
    int global_col_id = offset + (bx + 1) * BLOCK_SIZE;
    int tx, ty, i;

    // Load data into local buffers
    #pragma omp parallel for private(tx, ty)
    for (ty = 0; ty < BLOCK_SIZE; ty++) {
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            peri_row[ty * BLOCK_SIZE + tx] = m[(offset + ty) * matrix_dim + global_col_id + tx];
            peri_col[ty * BLOCK_SIZE + tx] = m[(global_row_id + ty) * matrix_dim + offset + tx];
        }
    }

    // Compute and update
    #pragma omp parallel for private(tx, ty, i)
    for (ty = 0; ty < BLOCK_SIZE; ty++) {
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            float sum = 0.0f;
            for (i = 0; i < BLOCK_SIZE; i++) {
                sum += peri_col[ty * BLOCK_SIZE + i] * peri_row[i * BLOCK_SIZE + tx];
            }
            m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
        }
    }
}

void lud_omp(float *m, int matrix_dim) {
    int i, bx, by;
    int num_blocks = matrix_dim / BLOCK_SIZE;

    for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        // Diagonal block
        lud_diagonal(m, matrix_dim, i);

        // Perimeter blocks
        #pragma omp parallel for private(bx)
        for (bx = 0; bx < (matrix_dim - i) / BLOCK_SIZE - 1; bx++) {
            lud_perimeter(m, matrix_dim, i, bx);
        }

        // Internal blocks
        #pragma omp parallel for private(bx, by)
        for (by = 0; by < (matrix_dim - i) / BLOCK_SIZE - 1; by++) {
            for (bx = 0; bx < (matrix_dim - i) / BLOCK_SIZE - 1; bx++) {
                lud_internal(m, matrix_dim, i, bx, by);
            }
        }
    }

    // Final diagonal block
    lud_diagonal(m, matrix_dim, matrix_dim - BLOCK_SIZE);
}
